type userAccountJoins[Q dialect.Joinable] struct {
	typ                           string
	UserForgotPasswordToken       modAs[Q, forgotPasswordTokenColumns]
	CreatedByPersonalAccessTokens modAs[Q, personalAccessTokenColumns]
	UpdatedByPersonalAccessTokens modAs[Q, personalAccessTokenColumns]
	CreatedByRepositories         modAs[Q, repositoryColumns]
	UpdatedByRepositories         modAs[Q, repositoryColumns]
	Organization                  modAs[Q, organizationColumns]
}

func (j userAccountJoins[Q]) aliasedAs(alias string) userAccountJoins[Q] {
	return buildUserAccountJoins[Q](buildUserAccountColumns(alias), j.typ)
}

func buildUserAccountJoins[Q dialect.Joinable](cols userAccountColumns, typ string) userAccountJoins[Q] {
	return userAccountJoins[Q]{
		typ: typ,
		UserForgotPasswordToken: modAs[Q, forgotPasswordTokenColumns]{
			c: ForgotPasswordTokens.Columns,
			f: func(to forgotPasswordTokenColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, ForgotPasswordTokens.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		CreatedByPersonalAccessTokens: modAs[Q, personalAccessTokenColumns]{
			c: PersonalAccessTokens.Columns,
			f: func(to personalAccessTokenColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, PersonalAccessTokens.Name().As(to.Alias())).On(
						to.CreatedBy.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		UpdatedByPersonalAccessTokens: modAs[Q, personalAccessTokenColumns]{
			c: PersonalAccessTokens.Columns,
			f: func(to personalAccessTokenColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, PersonalAccessTokens.Name().As(to.Alias())).On(
						to.UpdatedBy.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		CreatedByRepositories: modAs[Q, repositoryColumns]{
			c: Repositories.Columns,
			f: func(to repositoryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Repositories.Name().As(to.Alias())).On(
						to.CreatedBy.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		UpdatedByRepositories: modAs[Q, repositoryColumns]{
			c: Repositories.Columns,
			f: func(to repositoryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Repositories.Name().As(to.Alias())).On(
						to.UpdatedBy.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Organization: modAs[Q, organizationColumns]{
			c: Organizations.Columns,
			f: func(to organizationColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Organizations.Name().As(to.Alias())).On(
						to.ID.EQ(cols.OrganizationID),
					))
				}

				return mods
			},
		},
	}
}
